import styled from 'styled-components';
import colors from '../constants/colors';
import fontSizes from '../constants/fontsize';

const Eyebrow = styled.span`
  display: inline-flex;
  align-items: center;
  gap: 0.55rem;
  text-transform: uppercase;
  letter-spacing: 0.26em;
  font-size: ${fontSizes.xs};
  color: ${colors.gold};
  margin-bottom: 0.95rem;

  &::before {
    content: '';
    width: 2.25rem;
    height: 1px;
    background: ${colors.gold};
  }
`;

const Title = styled.h2`
  margin: 0;
  font-size: clamp(${fontSizes['2xl']}, 1.8vw, ${fontSizes['4xl']});
  line-height: 1.1;
  color: ${colors.navy};
`;

const Subtitle = styled.p`
  margin: 0.85rem 0 0;
  max-width: 44rem;
  font-size: ${fontSizes.md};
  line-height: 1.75;
  color: ${colors.grayMid};
`;

const SectionTitleWrap = styled.div`
  text-align: ${({ $align }) => ($align === 'left' ? 'left' : 'center')};
  max-width: ${({ $align }) => ($align === 'left' ? '48rem' : '54rem')};
  margin: 0 auto ${({ $compact }) => ($compact ? '2rem' : '3rem')};
`;

export default function SectionTitle({ eyebrow, title, subtitle, align = 'center', compact = false }) {
  return (
    <SectionTitleWrap $align={align} $compact={compact}>
      <Eyebrow>{eyebrow}</Eyebrow>
      <Title>{title}</Title>
      {subtitle ? <Subtitle>{subtitle}</Subtitle> : null}
    </SectionTitleWrap>
  );
}
